from typing import List

class Solution:
    def findOcurrences(self, text: str, first: str, second: str) -> List[str]:
        words = text.split()
        result = []

        for i in range(len(words) - 2):
            if words[i] == first and words[i + 1] == second:
                result.append(words[i + 2])

        return result
```

This solution splits the input text into words and then iterates through the list of words to check for occurrences of the pattern "first second third". If the pattern is found, it appends the third word to the result list.
